141‚Üíinternal class OptionalFormatStructure<in T>(
142‚Üí    val onZero: String,
143‚Üí    val format: FormatStructure<T>,
144‚Üí) : NonConcatenatedFormatStructure<T> {
145‚Üí    override fun toString(): String = "Optional($onZero, $format)"
146‚Üí
147‚Üí    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148‚Üí        PropertyWithDefault.fromField(field)
149‚Üí    }
150‚Üí
151‚Üí    override fun equals(other: Any?): Boolean =
152‚Üí        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153‚Üí
154‚Üí    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155‚Üí
156‚Üí    override fun parser(): ParserStructure<T> = ParserStructure(
157‚Üí        operations = emptyList(),
158‚Üí        followedBy = listOf(
159‚Üí            format.parser(),
160‚Üí            listOf(
161‚Üí                ConstantFormatStructure<T>(onZero).parser(),
162‚Üí                ParserStructure(
163‚Üí                    if (fields.isEmpty()) {
164‚Üí                        emptyList()
165‚Üí                    } else {
166‚Üí                        listOf(
167‚Üí                            UnconditionalModification {
168‚Üí                                for (field in fields) {
169‚Üí                                    field.assignDefault(it)
170‚Üí                                }
171‚Üí                            }
172‚Üí                        )
173‚Üí                    },
174‚Üí                    emptyList()
175‚Üí                )
176‚Üí            ).concat()
177‚Üí        )
178‚Üí    )
179‚Üí
180‚Üí    override fun formatter(): FormatterStructure<T> {
181‚Üí        val formatter = format.formatter()
182‚Üí        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
183‚Üí        return if (predicate is Truth) {
184‚Üí            ConstantStringFormatterStructure(onZero)
185‚Üí        } else {
186‚Üí            ConditionalFormatter(
187‚Üí                listOf(
188‚Üí                    predicate::test to ConstantStringFormatterStructure(onZero),
189‚Üí                    Truth::test to formatter
190‚Üí                )
191‚Üí            )
192‚Üí        }
193‚Üí    }
194‚Üí
195‚Üí    private class PropertyWithDefault<in T, E> private constructor(
196‚Üí        private val accessor: Accessor<T, E>,
197‚Üí        private val defaultValue: E
198‚Üí    ) {
199‚Üí        companion object {
200‚Üí            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
201‚Üí                val default = field.defaultValue
202‚Üí                require(default != null) {
203‚Üí                    "The field '${field.name}' does not define a default value"
204‚Üí                }
205‚Üí                return PropertyWithDefault(field.accessor, default)
206‚Üí            }
207‚Üí        }
208‚Üí
209‚Üí        inline fun assignDefault(target: T) {
210‚Üí            accessor.trySetWithoutReassigning(target, defaultValue)
211‚Üí        }
212‚Üí
213‚Üí        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
214‚Üí    }
215‚Üí}
